/**
 * Partial Sort implementation.
 * Returns the smallest k elements of the array in sorted order.
 * If k >= len(arr), returns the fully sorted array.
 * @param arr the input vector
 * @param k the number of smallest elements to return
 * @returns a sorted vector containing the k smallest elements
 */
std::vector<int> partial_sort(std::vector<int> arr, int k) {
    if (k <= 0) {
        return {};
    }
    if (k >= static_cast<int>(arr.size())) {
        std::sort(arr.begin(), arr.end());
        return arr;
    }

    std::partial_sort(arr.begin(), arr.begin() + k, arr.end());
    arr.resize(k);
    return arr;
}

