    {
        public static int[] Sort(int[] arr, int k)
        {
            if (arr == null || k <= 0)
            {
                return new int[0];
            }
            if (k >= arr.Length)
            {
                int[] result = (int[])arr.Clone();
                Array.Sort(result);
                return result;
            }

            // A simple implementation using LINQ.
